mapper.select:
WITH RECURSIVE category_path AS ( -- 起始分类 SELECT , 0 as path_level FROM tb_category c WHERE c.category_id = #{categoryId}
UNION ALL
-- 递归查找父分类 SELECT p.category_id, p.category_name, p.category_name_en, p.parent_id, p.category_level, p.sort_order, cp.path_level + 1 FROM tb_category p INNER JOIN category_path cp ON p.category_id = cp.parent_id WHERE p.parent_id != 0 ) SELECT category_id, category_name, category_name_en, parent_id, category_level, sort_order FROM category_path ORDER BY path_level DESC
